() => {
  const html = document.documentElement.innerHTML;
  const re = /https?:\/\/[^"'\s)]*meandlia\.com[^"'\s)]*/gi;
  const found = [...new Set((html.match(re)||[]))].slice(0,25);
  const anchors = [...document.querySelectorAll('a[href*=meandlia]')].map(a=>a.href).slice(0,15);
  const og = (document.querySelector('meta[property="og:url"]')||{}).content||null;
  const bodyStart = (document.body? document.body.innerText : '').slice(0,300);
  return { onPin: location.href, title: document.title, ogUrl: og, anchorsToSite: anchors, meandliaUrls: found, wall: /log in|sign up to see/i.test(bodyStart) };
}

